<!DOCTYPE html><html><head><meta http-equiv="Content-Type" content="text/html; charset=utf-8"/><title>Daftar Pengguna</title><style>body{font-family:Arial,sans-serif;font-size:10px;}table{width:100%;border-collapse:collapse;}th,td{border:1px solid #000;padding:4px;text-align:left;}th{background-color:#f0f0f0;font-weight:bold;}h2{text-align:center;}</style></head><body><h2>Daftar Pengguna</h2><table><thead><tr><th>No</th><th>Nama</th><th>Username</th><th>Email</th><th>Unit Kerja</th><th>Role</th><th>Dibuat</th></tr></thead><tbody>@foreach($users as $user)<tr><td>{{$loop->iteration}}</td><td>{{$user->nama_pengguna}}</td><td>{{$user->username}}</td><td>{{$user->email}}</td><td>{{$user->unit_kerja??"-"}}</td><td>{{ucfirst($user->role)}}</td><td>{{$user->created_at->format("d-m-Y")}}</td></tr>@endforeach</tbody></table><p style="text-align:right;margin-top:20px;">Dicetak: {{date("d-m-Y H:i:s")}}</p></body></html>